import React, { useState, useRef, useEffect } from 'react';
import { Check, Star, ChevronDown, AlertTriangle, MessageCircle, Users, Clock } from 'lucide-react';

const TodoItem = ({ 
  todo, 
  onToggleComplete, 
  onToggleStar, 
  onDelete, 
  onSelect,
  onUpdatePriority 
}) => {
  const [showPriorityDropdown, setShowPriorityDropdown] = useState(false);
  const dropdownRef = useRef(null);

  const priorities = [
    { value: 'High', label: 'High', color: 'text-red-500', borderColor: 'border-red-500' },
    { value: 'Medium', label: 'Medium', color: 'text-yellow-500', borderColor: 'border-yellow-500' },
    { value: 'Low', label: 'Low', color: 'text-green-500', borderColor: 'border-green-500' },
    { value: 'None', label: 'None', color: 'text-neutral-500', borderColor: 'border-neutral-500' }
  ];

  const currentPriority = priorities.find(p => p.value === (todo.priority || 'None'));

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setShowPriorityDropdown(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const handleItemClick = (e) => {
    // Don't trigger onSelect if clicking on priority badge area
    if (e.target.closest('.priority-badge')) {
      return;
    }
    onSelect(todo);
  };

  const handlePriorityClick = (e) => {
    e.stopPropagation();
    setShowPriorityDropdown(!showPriorityDropdown);
  };

  const handlePrioritySelect = (priority) => {
    onUpdatePriority(todo.id, priority.value);
    setShowPriorityDropdown(false);
  };

  const handleStarClick = (e) => {
    e.stopPropagation();
    onToggleStar(todo.id);
  };

  const handleCheckboxClick = (e) => {
    e.stopPropagation();
    onToggleComplete(todo.id);
  };

  return (
    <div
      className={`border rounded-lg p-4 hover:bg-neutral-800 transition-colors cursor-pointer group ${
        todo.missed 
          ? 'border-amber-600/50 bg-amber-900/10' 
          : 'border-neutral-700'
      }`}
      onClick={handleItemClick}
    >
      <div className="flex items-start gap-3">
        {/* Checkbox */}
        <button
          onClick={handleCheckboxClick}
          className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-colors ${
            todo.completed 
              ? 'bg-green-500 border-green-500' 
              : 'border-neutral-400 hover:border-white'
          }`}
        >
          {todo.completed && <Check className="w-3 h-3 text-white" />}
        </button>

        {/* Content */}
        <div className="flex-1">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              {todo.missed && (
                <AlertTriangle className="w-4 h-4 text-amber-500" />
              )}
              <span className={`text-white ${todo.completed ? 'line-through opacity-60' : ''}`}>
                {todo.description}
              </span>
            </div>

            <div className="flex items-center gap-3">
              <span className="text-neutral-400 text-sm">{todo.time}</span>

              {/* Priority Badge with Dropdown - Similar to UserCard status badge */}
              <div className="relative priority-badge" ref={dropdownRef}>
                <button
                  onClick={handlePriorityClick}
                  className={`flex items-center space-x-1 px-2 py-1 border rounded text-xs font-medium transition-colors hover:opacity-80 ${currentPriority.color} ${currentPriority.borderColor}`}
                >
                  <span>{currentPriority.label}</span>
                  <ChevronDown className="w-3 h-3" />
                </button>

                {showPriorityDropdown && (
                  <div className="absolute right-0 top-full mt-1 bg-neutral-800 border border-neutral-600 rounded-lg shadow-lg z-10 min-w-[100px]">
                    {priorities.map((priority) => (
                      <button
                        key={priority.value}
                        onClick={() => handlePrioritySelect(priority)}
                        className="w-full flex items-center space-x-2 px-3 py-2 text-sm text-white hover:bg-neutral-800 transition-colors first:rounded-t-lg last:rounded-b-lg"
                      >
                        <div className={`w-3 h-3 rounded border ${priority.borderColor} ${priority.color.replace('text-', 'bg-')}`}></div>
                        <span>{priority.label}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>

              {/* Quick Action Buttons - Appear on hover */}
              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    // Quick comment action
                    console.log('Quick comment for todo:', todo.id);
                  }}
                  className="p-1 text-neutral-400 hover:text-white transition-colors"
                  title="Add comment"
                >
                  <MessageCircle className="w-4 h-4" />
                </button>

                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    // Quick assign action
                    console.log('Quick assign for todo:', todo.id);
                  }}
                  className="p-1 text-neutral-400 hover:text-white transition-colors"
                  title="Assign to someone"
                >
                  <Users className="w-4 h-4" />
                </button>

                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    // Quick reminder action
                    console.log('Quick reminder for todo:', todo.id);
                  }}
                  className="p-1 text-neutral-400 hover:text-white transition-colors"
                  title="Set reminder"
                >
                  <Clock className="w-4 h-4" />
                </button>
              </div>

              {/* Star Icon */}
              <button
                onClick={handleStarClick}
                className={`transition-colors ${
                  todo.starred 
                    ? 'text-white' 
                    : 'text-neutral-600 hover:text-white'
                }`}
              >
                <Star className={`w-4 h-4 ${todo.starred ? 'fill-current' : ''}`} />
              </button>
            </div>
          </div>

          {/* Steps indicator with progress bar */}
          {todo.steps && todo.steps.length > 0 && (
            <div className="mt-2 space-y-1">
              <div className="flex items-center justify-between text-sm text-neutral-400">
                <span>Tasks</span>
                <span>{todo.steps.filter(step => step.completed).length} of {todo.steps.length}</span>
              </div>
              <div className="w-full bg-neutral-700 rounded-full h-1.5">
                <div 
                  className="bg-green-500 h-1.5 rounded-full transition-all duration-300"
                  style={{ 
                    width: `${(todo.steps.filter(step => step.completed).length / todo.steps.length) * 100}%` 
                  }}
                ></div>
              </div>
            </div>
          )}

          {/* Comments indicator */}
          {todo.comments && todo.comments.length > 0 && (
            <div className="mt-2 flex items-center gap-1 text-sm text-neutral-400">
              <MessageCircle className="w-3 h-3" />
              <span>{todo.comments.length} comment{todo.comments.length !== 1 ? 's' : ''}</span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default TodoItem;
